import java.util.Scanner;

public class SecureBufferHandling {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        // Determine the safe length of user input to copy into the buffer
        int safeLength = Math.min(userInput.length(), 10);

        char[] buffer = new char[10];

        // Copy only up to safeLength characters from user input into buffer
        userInput.getChars(0, safeLength, buffer, 0);

        // Print out the contents of the buffer safely
        for (int i = 0; i < safeLength; i++) {
            System.out.print(buffer[i]);
        }

        scanner.close();
    }
}

### Explanation:
취약유형: Buffer Overflow
